// src/pages/LabourDashboard.jsx

import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function LabourDashboard() {

  const user = JSON.parse(localStorage.getItem("user") || "{}");

  const [requests, setRequests] = useState([]);
  const [price, setPrice] = useState({});

  useEffect(() => {
    getRequests();
  }, []);

  const getRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/request/labour/${user._id}`
      );
      setRequests(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  const respondRequest = async (id, action) => {
    try {
      await axios.put(
        `http://localhost:5000/api/request/labour-response/${id}`,
        {
          price: price[id] || 0,
          action
        }
      );
      getRequests();
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>

        <div style={styles.card}>

          <h2 style={styles.heading}>Incoming Requests</h2>

          {requests.length === 0 && (
            <p style={styles.empty}>No requests found</p>
          )}

          {requests.map((req) => (
            <div key={req._id} style={styles.requestCard}>

              {/* TOP ROW */}
              <div style={styles.topRow}>
                <h3 style={styles.name}>{req.customerName}</h3>
                <span style={styles.badge}>{req.status}</span>
              </div>

              {/* DETAILS */}
              <div style={styles.details}>
                <p>Work: {req.workType}</p>
                <p>Location: {req.location}</p>
                <p>Date: {req.date}</p>
                <p>Customer Decision: {req.customerDecision}</p>
              </div>

              {/* PRICE INPUT */}
              <input
                type="number"
                placeholder="Enter Price (₹)"
                style={styles.input}
                value={price[req._id] || ""}
                onChange={(e) =>
                  setPrice({
                    ...price,
                    [req._id]: e.target.value
                  })
                }
              />

              {/* BUTTONS */}
              {req.status === "Pending" && (
                <div style={styles.btnRow}>

                  <button
                    style={styles.acceptBtn}
                    onClick={() => respondRequest(req._id, "Accepted")}
                  >
                    Accept
                  </button>

                  <button
                    style={styles.rejectBtn}
                    onClick={() => respondRequest(req._id, "Rejected")}
                  >
                    Reject
                  </button>

                </div>
              )}

              {/* FEEDBACK */}
              {req.feedback && (
                <div style={styles.feedbackBox}>
                  <p style={styles.rating}>
                    ⭐ {req.feedback.rating}/5
                  </p>
                  <p style={styles.comment}>
                    {req.feedback.comment}
                  </p>
                </div>
              )}

            </div>
          ))}

        </div>
      </div>
    </div>
  );
}

/* ================= STYLES ================= */

const styles = {

  page: {
    background: "#0b0f19",
    minHeight: "100vh",
    color: "white"
  },

  container: {
    maxWidth: "900px",
    margin: "auto",
    padding: "20px"
  },

  card: {
    background: "#111827",
    borderRadius: "12px",
    border: "1px solid #1f2937",
    padding: "20px"
  },

  heading: {
    color: "#f97316",
    textAlign: "center",
    marginBottom: "20px"
  },

  requestCard: {
    background: "#1f2937",
    borderRadius: "10px",
    padding: "15px",
    marginBottom: "15px",
    border: "1px solid #374151"
  },

  topRow: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "8px"
  },

  name: {
    margin: 0,
    color: "#f97316",
    fontSize: "16px"
  },

  badge: {
    background: "#374151",
    padding: "4px 10px",
    borderRadius: "6px",
    fontSize: "12px"
  },

  details: {
    fontSize: "13px",
    color: "#d1d5db",
    lineHeight: "1.6"
  },

  input: {
    width: "100%",
    marginTop: "10px",
    padding: "12px",
    borderRadius: "8px",
    border: "1px solid #374151",
    background: "#111827",
    color: "white",
    outline: "none"
  },

  btnRow: {
    display: "flex",
    gap: "10px",
    marginTop: "12px"
  },

  acceptBtn: {
    flex: 1,
    padding: "10px",
    background: "#16a34a",
    border: "none",
    borderRadius: "8px",
    color: "white",
    cursor: "pointer"
  },

  rejectBtn: {
    flex: 1,
    padding: "10px",
    background: "#dc2626",
    border: "none",
    borderRadius: "8px",
    color: "white",
    cursor: "pointer"
  },

  feedbackBox: {
    marginTop: "12px",
    padding: "10px",
    borderRadius: "8px",
    background: "#0f172a",
    border: "1px solid #374151"
  },

  rating: {
    margin: 0,
    color: "#f97316",
    fontWeight: "bold"
  },

  comment: {
    margin: "5px 0 0 0",
    color: "#d1d5db"
  },

  empty: {
    textAlign: "center",
    color: "#9ca3af"
  }
};
